 function Err({x}:{x:any}){return <div style={{fontSize:11,color:T.err,marginTop:4}}>{x}</div>}
 const Field=useMemo(()=>memo(function MemoField({label,value,onChange,ph,type='text',required=false}:any){const [local,setLocal]=useState(value??'');const inputRef=useRef<HTMLInputElement|null>(null);const isNumeric=/phone|whatsapp|شماره|کارت|شبا|قیمت|price|کد|postal|zip|سن|قد|وزن|age|height|weight/i.test(String(label||''));useEffect(()=>setLocal(value??''),[value]);const cleanNumeric=(s:any)=>p2e(s).replace(/[^0-9]/g,'');const handle=useCallback((e:any)=>setLocal(isNumeric?cleanNumeric(e.target.value):e.target.value),[isNumeric]);const commit=useCallback(()=>onChange(isNumeric?cleanNumeric(local):local),[onChange,local,isNumeric]);return <div style={{marginBottom:13}}><label style={S.lbl}>{trVal(label)}{required&&<span style={{color:T.err,marginInlineStart:4}}>*</span>}</label><input ref={inputRef} inputMode={isNumeric?'numeric':undefined} type={type} style={S.inp} value={local} onChange={handle} onBlur={commit} placeholder={trVal(ph)}/></div>}),[S,trVal,T.err]);
 const SelectBox=useMemo(()=>memo(function MemoSelectBox({label,items,val,setVal,multi=false}:any){const [open,setOpen]=useState(false); const txt=multi?(val||[]).join('، '):val; const choose=useCallback((it:string)=>{if(multi)setVal((val||[]).includes(it)?val.filter((x:string)=>x!==it):[...(val||[]),it]); else {setVal(it);setOpen(false)}},[multi,setVal,val]); return <div><label style={S.lbl}>{label}</label><Popup open={open} onClose={()=>setOpen(false)} T={T} trigger={<button onClick={()=>setOpen((v:boolean)=>!v)} style={{...S.inp,textAlign:'inherit',cursor:'pointer',display:'flex',justifyContent:'space-between',alignItems:'center'}}><span style={{fontSize:13,color:txt?T.txt:T.mut,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{txt?String(txt).split('، ').map(trVal).join('، '):t(cfg,lang,'select','انتخاب کنید...')}</span><span>⌄</span></button>}>{items.map((it:string)=><button key={it} onClick={()=>choose(it)} style={{display:'block',width:'100%',padding:'9px 10px',background:(multi?val?.includes(it):val===it)?T.soft:'transparent',border:0,borderRadius:9,color:(multi?val?.includes(it):val===it)?T.acc:T.txt,cursor:'pointer',fontFamily:'inherit',textAlign:'right',fontSize:13}}>{trVal(it)}</button>)}</Popup></div>}),[S,T,cfg,lang,trVal]);
 // بازطراحی: تیک بزرگ موفقیت با گرادیان نرم، کارت‌های داخلی با سایه inset به‌جای بردر تیز
 function SuccessPage(){return <div style={{...S.page,flexDirection:'column',alignItems:'center',justifyContent:'flex-start',paddingBottom:16}}><Helmet><title>ثبت موفقیت‌آمیز فرم مشاوره | زینالیکید</title><meta name="description" content="فرم مشاوره شما با موفقیت ثبت شد. کارشناسان ما طی ۲۴ تا ۴۸ ساعت با شما تماس می‌گیرند." /><meta name="robots" content="noindex, follow" /></Helmet><style>{css}</style><Header T={T} lang={lang} setLang={setLang}/><SuccessHamburger T={T} lang={lang} onForm={resetForm} onCourses={goToCourses} onContact={()=>setShowCt(v=>!v)}/><div style={{...S.card,maxWidth:460,textAlign:'center',padding:'20px 18px',marginTop:64}}><div style={{margin:'2px auto 12px',width:78,height:78,borderRadius:'50%',background:'linear-gradient(135deg,#10b981,#06b6d4)',display:'flex',alignItems:'center',justifyContent:'center',boxShadow:'0 16px 38px rgba(16,185,129,.3), 4px 4px 10px rgba(0,0,0,.08)',animation:'modalIn .4s ease both'}}><svg width="44" height="44" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="2.8" strokeLinecap="round" strokeLinejoin="round"><path d="M20 6 9 17l-5-5"/></svg></div><h2 style={{color:T.ttl,fontSize:17,margin:'0 0 5px',fontWeight:800}}>{publicText('successMsg')}</h2><p style={{color:T.mut,fontSize:12.5,lineHeight:1.8,margin:'0 0 8px'}}>{publicText('successSubMsg')}</p>{lastTrack&&<div style={{background:'#facc1518',borderRadius:12,padding:'9px 11px',marginBottom:8,textAlign:'right',boxShadow:T.neuIn}}><div style={{fontSize:11,color:'#ca8a04',fontWeight:800,lineHeight:1.8,marginBottom:3}}>{lang==='en'?'Please save or write down your tracking code for the next steps:':'حتماً کد پیگیری را برای مراحل بعدی ذخیره یا یادداشت بفرمایید:'}</div><div style={{display:'flex',alignItems:'center',justifyContent:'center',gap:8}}><span style={{fontSize:10,color:T.mut}}>{lang==='en'?'Your tracking code:':'کد پیگیری شما:'} </span><b dir="ltr" onClick={copyTrack} title={lang==='en'?'Click to copy':'برای کپی کلیک کنید'} style={{fontSize:17,color:T.acc,letterSpacing:'2px',fontFamily:'monospace,-apple-system,"Courier New"',cursor:'pointer'}}>{lastTrack}</b>{/* اصلاح ۱۷: فقط تیک سبز پس از کپی، بدون متن «کپی شد» */}<button onClick={copyTrack} title="کپی" style={{width:26,height:26,borderRadius:8,display:'flex',alignItems:'center',justifyContent:'center',cursor:'pointer',background:trackCopied?'#16a34a':'rgba(255,255,255,.9)',color:trackCopied?'#fff':'#111',fontSize:13,transition:'all .3s ease',flexShrink:0,border:0,fontFamily:'inherit'}}>{trackCopied?'✓':'⧉'}</button></div></div>}{cfg.timeSlots?.length>0&&<div style={{background:T.soft,borderRadius:14,padding:'9px 11px',marginBottom:8,textAlign:'right',boxShadow:T.neuIn}}><b style={{fontSize:11.5,color:T.txt}}>{publicText('timeSlotLabel')}</b><div style={{display:'flex',gap:6,flexWrap:'wrap',marginTop:7,justifyContent:'center'}}>{cfg.timeSlots.map((x:string)=><button key={x} onClick={()=>updateTimeSlot(tsSlot===x?'':x)} style={{padding:'6px 12px',borderRadius:20,border:'none',background:tsSlot===x?T.soft:T.card,color:tsSlot===x?T.acc:T.mut,cursor:'pointer',fontFamily:'inherit',fontSize:12,boxShadow:tsSlot===x?T.neuIn:T.neuOut}}>{trVal(x)}</button>)}</div></div>}<button style={{...S.btn,marginBottom:8,padding:14,fontSize:16}} onClick={goToCourses}><MiniIcon type="course" T={{acc:'#fff'}}/> {publicText('directCourseBtn')}</button><div style={{display:'grid',gridTemplateColumns:showContactOn('consultSuccess')?'1fr 1fr':'1fr',gap:8}}><button style={{...S.btnGhost,padding:11}} onClick={resetForm}>{publicText('newFormBtn')}</button>{showContactOn('consultSuccess')&&<button style={{...S.btnGhost,padding:11}} onClick={()=>setShowCt(v=>!v)}>{publicText('contactBtn')}</button>}</div><p style={{color:T.mut,fontSize:getTrustFontSize(String(successMsgRnd),13),lineHeight:2,margin:'8px 0 0',textAlign:'right',background:T.soft,borderRadius:12,padding:'9px 11px',boxShadow:T.neuIn,overflow:'hidden'}}>{successMsgRnd}</p>{showCt&&showContactOn('consultSuccess')&&<ContactPanel cfg={cfg} T={T} lang={lang}/>}</div><div style={{marginTop:'auto',width:'100%',maxWidth:600}}><Footer cfg={cfg} T={T} lang={lang}/></div>{copyToast&&<div style={{position:'fixed',bottom:18,left:'50%',transform:'translateX(-50%)',zIndex:9999,background:T.pop,border:`1px solid ${copyToast.includes('نشد')||copyToast.includes('failed')?T.err:T.ok}`,color:copyToast.includes('نشد')||copyToast.includes('failed')?T.err:T.ok,borderRadius:12,padding:'10px 16px',fontSize:13,fontWeight:800,boxShadow:'0 14px 35px rgba(0,0,0,.18)',animation:'fadeSlide .35s ease both'}}>{copyToast}</div>}</div>}
 // بازطراحی: پس‌زمینه ممفیس تزئینی روی صفحات فرم و موفقیت
 if(view==='form')return <>{<MemphisBg T={T}/>}{FormPage()}</>; if(view==='success')return <>{<MemphisBg T={T}/>}{SuccessPage()}</>; return null;
